import * as WebBrowser from 'expo-web-browser';
import { makeRedirectUri, useAuthRequest } from 'expo-auth-session';
import { Google } from 'expo-auth-session/providers/google';

WebBrowser.maybeCompleteAuthSession();

const useGoogleAuth = () => {
  const [request, response, promptAsync] = Google.useAuthRequest({
    clientId: process.env.EXPO_PUBLIC_GOOGLE_CLIENT_ID!,
    iosClientId: process.env.EXPO_PUBLIC_GOOGLE_IOS_CLIENT_ID,
    androidClientId: process.env.EXPO_PUBLIC_GOOGLE_ANDROID_CLIENT_ID,
    redirectUri: makeRedirectUri({
      scheme: 'monapp',
      path: 'oauthredirect',
    }),
  });

  const signInWithGoogle = async () => {
    try {
      const result = await promptAsync();
      if (result?.type === 'success') {
        const { authentication } = result;
        const accessToken = authentication?.accessToken;

        // Récupérer les infos utilisateur avec le token
        const userInfoResponse = await fetch(
          'https://www.googleapis.com/userinfo/v2/me',
          {
            headers: { Authorization: `Bearer ${accessToken}` },
          }
        );
        const userInfo = await userInfoResponse.json();

        return {
          id: userInfo.id,
          email: userInfo.email,
          name: userInfo.name,
          picture: userInfo.picture,
          accessToken,
        };
      }
      return null;
    } catch (error) {
      console.error('Google Sign-In error:', error);
      throw error;
    }
  };

  return { signInWithGoogle, request };
};

export default useGoogleAuth;
```

**Prérequis Apple Developer :**
- Compte développeur Apple actif.
- Activer le 'Sign in with Apple' dans le Certificates, Identifiers & Profiles.
- Créer un Service ID pour l'authentification web (si nécessaire).
- Ajouter le domaine et l'URL de retour (ex: `https://monapp.com/callback`).

**Configuration dans `app.json` :**
```json
{
  "expo": {
    "ios": {
      "usesAppleSignIn": true,
      "bundleIdentifier": "com.monapp.ecommerce",
      "config": {
        "usesNonExemptEncryption": false
      }
    }
  }
}
```

**Package à installer :**
```bash
npx expo install expo-apple-authentication
```

