import * as AppleAuthentication from 'expo-apple-authentication';

async function signInWithApple() {
  try {
    const credential = await AppleAuthentication.signInAsync({
      requestedScopes: [
        AppleAuthentication.AppleAuthenticationScope.FULL_NAME,
        AppleAuthentication.AppleAuthenticationScope.EMAIL,
      ],
    });

    // credential contient :
    // - user (identifiant unique Apple)
    // - email (si partagé)
    // - fullName (prénom, nom)
    // - identityToken (JWT à envoyer au backend)
    // - authorizationCode
    // - realUserStatus

    const { user, email, fullName, identityToken } = credential;

    // Envoyer identityToken au backend pour vérification
    const response = await fetch('https://api.monapp.com/auth/apple', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ identityToken, user, email, name: fullName?.givenName }),
    });

    const data = await response.json();
    return data;
  } catch (error) {
    if (error.code === 'ERR_CANCELED') {
      // L'utilisateur a annulé
      return null;
    }
    throw error;
  }
}
