import * as SecureStore from 'expo-secure-store';
import useAuthStore from '../store/authStore';

interface SocialLoginResponse {
  user: User;
  token: string;
  isNewUser: boolean;
  needsLinking?: boolean;
  existingProvider?: string;
}

async function handleSocialLogin(provider: 'google' | 'apple', providerToken: string, userInfo: any) {
  try {
    // 1. Appeler le backend avec le token
    const response = await fetch('https://api.monapp.com/auth/social', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        provider,
        providerToken,
        email: userInfo.email,
        name: userInfo.name || userInfo.fullName?.givenName,
        picture: userInfo.picture,
      }),
    });

    const data: SocialLoginResponse = await response.json();

    // 2. Cas où un compte existe déjà avec un autre fournisseur
    if (data.needsLinking) {
      return { 
        needsLinking: true, 
        existingProvider: data.existingProvider,
        email: userInfo.email 
      };
    }

    // 3. Stockage sécurisé du token
    await SecureStore.setItemAsync('access_token', data.token);

    // 4. Mise à jour du store Zustand
    useAuthStore.getState().setUser(data.user);
    useAuthStore.getState().setToken(data.token);

    // 5. Notification utilisateur
    if (data.isNewUser) {
      Toast.show(`Bienvenue ${data.user.name} ! Votre compte a été créé.`);
    } else {
      Toast.show(`Bon retour ${data.user.name} !`);
    }

    return { success: true, isNewUser: data.isNewUser };
  } catch (error) {
    console.error('Social login error:', error);
    throw error;
  }
}

// Fonction de liaison de comptes
async function linkAccount(provider: 'google' | 'apple', providerToken: string, email: string) {
  const currentToken = await SecureStore.getItemAsync('access_token');
  const response = await fetch('https://api.monapp.com/auth/link', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${currentToken}`,
    },
    body: JSON.stringify({ provider, providerToken, email }),
  });

  return response.json();
}
