import { useAutoRefresh } from 'expo-auth-session';

// Dans le composant utilisant Google.useAuthRequest
const [request, response, promptAsync] = Google.useAuthRequest({
  clientId: GOOGLE_CLIENT_ID,
  redirectUri,
  // Activer le refresh automatique
  usePKCE: true,
});

useEffect(() => {
  if (response?.type === 'success') {
    const { authentication } = response;
    // authentication.refreshToken est disponible
    // authentication.accessToken expire après 1h

    // Stocker le refresh token dans SecureStore
    SecureStore.setItemAsync('google_refresh_token', authentication.refreshToken);
  }
}, [response]);

// Rafraîchissement automatique via un intercepteur Axios
api.interceptors.response.use(
  response => response,
  async error => {
    if (error.response?.status === 401) {
      const refreshToken = await SecureStore.getItemAsync('google_refresh_token');
      const newTokens = await refreshGoogleToken(refreshToken);
      await SecureStore.setItemAsync('access_token', newTokens.accessToken);
      error.config.headers.Authorization = `Bearer ${newTokens.accessToken}`;
      return api(error.config);
    }
    return Promise.reject(error);
  }
);
